import { Component, h, Prop, State, Watch, Event, EventEmitter, Method } from '@stencil/core';
import * as messages from './messages.json';
import { States, getStatus } from './states';

@Component({
  tag: 'bst-sign-otp',
  styleUrl: 'bst-sign-otp.scss',
  shadow: true,
})
export class BstSignOTP {
  /*
    
  [opcionales]: 
  - La composicion de las urls sería mejor hacerlas con alguna utilidad que evite repetir '/'
  - Las llamadas a apis pueden establecerse en un fichero (por ejemplo signservice.ts)
  - Crear pruebas unitarias para el componente. Para esto se necesitará una propiedad que permita mockear estados del UI
  - Dividir el componente en varios componentes más pequeños, por ejemplo:
      - Input: para el input del OTP
      - Button: para el botón de validación del OTP
      - Link: para el enlace de reenvio del OTP

  */

  /******************************************************************
   * PROPERTIES
   ******************************************************************/
  /**
   * The Signature ID
   */
  @Prop() idSignature: string;

  /**
   * Base URL
  */
  @Prop() urlSignatureIssuer: string;

  /**
   * Language to use in the component
   */
  @Prop() locale: string = 'es';

  /**
   * Show the link to the person not present
   */
  @Prop() showNoPresentLink: boolean = false;

  /**
   * Show the resend OTP button
   */
  @Prop() showResendOtpLink: boolean = false;

  /**
   * Number of retries to initialize the component
   */
  @Prop() initRetries: number = 3;

  /**
   * Number of seconds to retry initializing the component
   */
  @Prop() initRetrySeconds: number = 5;

  /**
   * Text to display in the "Validate" button
   */
  @Prop() textButton?: string;

  /**
   * Text to display as placeholder in the input
   */
  @Prop() textPlaceholder?: string;

  /**
   * Text to display OTP PIN for testing purposes
   */
  @Prop() otpPin?: string;

  /**
   * Enable mock mode for testing purposes
   */
  @Prop() mockModeEnabled: boolean = false;

  /**
   * Mock state for testing purposes, must be used with mockModeEnabled
   */
  @Prop() mockState: number = 0;

  /******************************************************************
   * STATES
   ******************************************************************/
  /**
   * The component internal state
   * 
   * 0 = loading component
   * 1 = initialized, not signed
   * 11 = initialized, OTP not valid
   * 15 = max attemps exceeded
   * 16 = expired or cancelled on initialization
   * 20 = error
   * 21 = error cancelled
   * 22 = error expired
   * 23 = error OTP_OK, signed
   * 24 = error resend OTP
   * 30 = component signed successfully
   * 
   */
  @State() state: number = 0;

  /**
   * OTP value entered by the user
   */
  @State() otpValue: string;

  /**
   * Boolean to indicate if the component is loading
   */
  @State() isLoading: boolean = false;

  /**
   * Number of retries to initialize the component (internal state)
   */
  @State() initRetriesState: number;

  /**
   * Language to use in the component (internal state)
   */
  @State() localeState: string;

  /******************************************************************
   * WATCHERS
   ******************************************************************/
  @Watch('locale')
  validateLocale(newValue: string) {
    if (newValue.toLocaleLowerCase() === 'en' || newValue.toLocaleLowerCase() === 'es') {
      this.localeState = newValue.toLocaleLowerCase();
    } else {
      console.warn(`[bst-sign-otp] Invalid locale '${newValue}' — falling back to 'es'.`);
      this.localeState = 'es';
    }
  }

  /******************************************************************
   * EVENT
   ******************************************************************/
  /**
   * Launches when the `bst-sign-otp` component is loaded
   */
  @Event({
    eventName: 'otpComponentLoaded',
    composed: true,
    cancelable: true,
    bubbles: true,
  }) otpComponentLoaded: EventEmitter<string>;
  eventEmitterOtpComponentLoaded(data?: string) {
    this.otpComponentLoaded.emit(data);
  }

  /**
   * Launches when the OTP is signed successfully
   */
  @Event({
    eventName: 'otpSignOK',
    composed: true,
    cancelable: true,
    bubbles: true,
  }) otpSignOK: EventEmitter<string>;
  eventEmitterOtpSignOK(data?: string) {
    this.otpSignOK.emit(data);
  }

  /**
   * Launches when the OTP signing fails
   */
  @Event({
    eventName: 'otpSignKO',
    composed: true,
    cancelable: true,
    bubbles: true,
  }) otpSignKO: EventEmitter<string>;
  eventEmitterOtpSignKO(data?: string) {
    this.otpSignKO.emit(data);
  }

  /**
   * Launches when the OTP is cancelled
   */
  @Event({
    eventName: 'otpCancelled',
    composed: true,
    cancelable: true,
    bubbles: true,
  }) otpCancelled: EventEmitter<string>;
  eventEmitterOtpCancelled(data?: string) {
    this.otpCancelled.emit(data);
  }

  /**
   * Launches when the OTP is expired
   */
  @Event({
    eventName: 'otpExpired',
    composed: true,
    cancelable: true,
    bubbles: true,
  }) otpExpired: EventEmitter<string>;
  eventEmitterOtpExpired(data?: string) {
    this.otpExpired.emit(data);
  }

  /**
   * Launches when the `not-present` button is clicked
   */
  @Event({
    eventName: 'otpNotPresent',
    composed: true,
    cancelable: true,
    bubbles: true,
  }) otpNotPresent: EventEmitter<string>;
  eventEmitterOtpNotPresent(data?: string) {
    this.otpNotPresent.emit(data);
  }

  /**
   * Launches when something goes wrong and/or the component cannot be initialized
   */
  @Event({
    eventName: 'otpError',
    composed: true,
    cancelable: true,
    bubbles: true,
  }) otpError: EventEmitter<string>;
  eventEmitterOtpError(data?: string) {
    this.otpError.emit(data);
  }

  /**
   * Launches when the "get status" request starts
   */
  @Event({
    eventName: 'otpInitStarted',
    composed: true,
    cancelable: true,
    bubbles: true,
  }) otpInitStarted: EventEmitter<string>;
  eventEmitterOtpInitStarted(data?: string) {
    this.otpInitStarted.emit(data);
  }

  /**
   * Launches when the "get status" request ends
   */
  @Event({
    eventName: 'otpInitEnded',
    composed: true,
    cancelable: true,
    bubbles: true,
  }) otpInitEnded: EventEmitter<string>;
  eventEmitterOtpInitEnded(data?: string) {
    this.otpInitEnded.emit(data);
  }

  /**
   * Launches when the "validate" request starts
   */
  @Event({
    eventName: 'otpValidatingStarted',
    composed: true,
    cancelable: true,
    bubbles: true,
  }) otpValidatingStarted: EventEmitter<string>;
  eventEmitterOtpValidatingStarted(data?: string) {
    this.otpValidatingStarted.emit(data);
  }

  /**
   * Launches when the "validate" request ends
   */
  @Event({
    eventName: 'otpValidatingEnded',
    composed: true,
    cancelable: true,
    bubbles: true,
  }) otpValidatingEnded: EventEmitter<string>;
  eventEmitterOtpValidatingEnded(data?: string) {
    this.otpValidatingEnded.emit(data);
  }

  /**
   * Launches when the "resend" request starts
   */
  @Event({
    eventName: 'otpResendStarted',
    composed: true,
    cancelable: true,
    bubbles: true,
  }) otpResendStarted: EventEmitter<string>;
  eventEmitterOtpResendStarted(data?: string) {
    this.otpResendStarted.emit(data);
  }

  /**
   * Launches when the "validate" request ends
   */
  @Event({
    eventName: 'otpResendEnded',
    composed: true,
    cancelable: true,
    bubbles: true,
  }) otpResendEnded: EventEmitter<string>;
  eventEmitterOtpResendEnded(data?: string) {
    this.otpResendEnded.emit(data);
  }

  /******************************************************************
   * METHODS
   ******************************************************************/
  componentWillLoad() {
    this.validateLocale(this.locale);
    this.eventEmitterOtpComponentLoaded();
    if (!this.mockModeEnabled) {
      this.initRetriesState = this.initRetries;
      this.initComponent();
    }
    else {
      this.setMockState(this.mockState);
    }
  }

  setMockState(newValue: number) {
    if (this.mockModeEnabled) {
      console.warn(`[bst-sign-otp] Mock mode enabled, using mockState: ${newValue}`);
      this.state = newValue;
    }
  }

  initComponent() {
    this.state = 0;
    const handleRetries = () => {
      if (this.initRetriesState > 0) {
        this.initRetriesState--;
        setTimeout(() => {
          console.log(`Retrying to initialize component, remaining retries: ${this.initRetriesState}`);
          this.initComponent();
        }, this.initRetrySeconds * 1000);
      } else {
        this.eventEmitterOtpError();
        this.state = 20; // error
      }
    }

    this.eventEmitterOtpInitStarted();
    fetch(this.urlSignatureIssuer + '/' + this.idSignature + '/status')
      .then(response => {
        if (response.status === 400 || response.status === 404) {
          handleRetries();
        } else {
          response.json()
            .then(response => {
              const responseStatus = getStatus(response);
              this.eventEmitterOtpInitEnded();
              switch (responseStatus) {
                case States.Init:
                  this.state = 1; // initialized, not signed
                  break;
                case States.Send:
                  this.state = 1; // initialized, not signed
                  break;
                case States.Error:
                  this.state = 20; // error
                  break;
                case States.Cancelled:
                  if (this.showResendOtpLink) {
                    this.state = 16;
                    this.eventEmitterOtpCancelled();
                  } else {
                    this.state = 21; // error cancelled
                    this.eventEmitterOtpCancelled();
                  }
                  break;
                case States.Expired:
                  if (this.showResendOtpLink) {
                    this.state = 16;
                    this.eventEmitterOtpExpired();
                  } else {
                    this.state = 22; // error expired
                    this.eventEmitterOtpExpired();
                  }
                  break;
                case States.Otp_Ok:
                case States.Signed:
                  this.state = 23; // error OTP_OK, signed
                  break;
              }
            });
        }
      })
      .catch(error => {
        console.error(error);
        handleRetries();
      });
  }

  resendOTP(clearinput: boolean) {
    this.state = 1;

    const requestOptions = {
      method: 'POST',
      redirect: 'follow' as const
    };

    this.isLoading = true;
    this.eventEmitterOtpResendStarted();
    fetch(this.urlSignatureIssuer + '/' + this.idSignature + '/resendOTP', requestOptions)
      .then(response => {
        if (clearinput) {
          this.otpValue = '';
        }
        if (response.status === 400) {
          this.state = 24; // error resend OTP
          this.eventEmitterOtpError();
          return;
        }
        if (response.status >= 500) {
          throw new Error();
        }
        response.json()
          .then(response => {
            //this.initComponent();
            this.otpPin = response;
            this.state = 1;
          })
      })
      .catch(error => {
        console.error(error);
        this.state = 20; // error
        this.eventEmitterOtpError();
      })
      .finally(() => {
        this.eventEmitterOtpResendEnded();
        this.isLoading = false;
      });
  }

  /******************************************************************
   * PUBLIC METHODS
   ******************************************************************/
  @Method()
  async setOtpValue(value: string) {
    this.otpValue = value;
  }

  @Method()
  async notPresent() {
    this.eventEmitterOtpNotPresent();
  }

  @Method()
  async validateOTP() {
    this.state = 1;

    if (this.otpValue === undefined || this.otpValue.trim() === '') {
      this.state = 11; // error empty / incorrect OTP
      return;
    }

    const myHeaders = new Headers();
    myHeaders.append('Content-Type', 'application/json');
    const options = {
      method: 'POST',
      headers: myHeaders,
      body: JSON.stringify({
        'idSignature': this.idSignature,
        'otp': this.otpValue
      }),
      redirect: 'follow' as const
    };

    this.isLoading = true;
    this.eventEmitterOtpValidatingStarted();
    fetch(this.urlSignatureIssuer + '/validateOTP', options)
      .then(response => {
        if (response.status === 400) {
          response.json()
            .then(response => {
              if (response === messages.BACKEND_ERRORS.OTP_CANCELLED) {
                this.state = 21;
                this.eventEmitterOtpCancelled();
              }
              if (response === messages.BACKEND_ERRORS.OTP_EXPIRED) {
                this.state = 22;
                this.eventEmitterOtpExpired();
              }
            });
          return;
        }
        if (response.status >= 500) {
          throw new Error();
        }
        response.json()
          .then(response => {
            if (response === "Correct") {
              this.state = 30;
              this.eventEmitterOtpSignOK();
            } else if (response === "Incorrect") {
              this.state = 11;
              this.eventEmitterOtpSignKO();
            } else if (response === "MaxFailedAttemps") {
              this.state = 15;
              this.eventEmitterOtpCancelled();
            } else {
              this.state = 20;
              this.eventEmitterOtpError();
            }
          })
      })
      .catch(error => {
        console.error(error);
        this.state = 20; // error
        this.eventEmitterOtpError();
      })
      .finally(() => {
        this.eventEmitterOtpValidatingEnded();
        this.isLoading = false
      });
  }

  /******************************************************************
   * RENDERS
   ******************************************************************/
  renderMessage() {
    const message = messages[this.localeState];

    switch (this.state) {
      case 0:
        return <div>{message.LOADING}</div>;
      case 1:
        return '';
      case 11:
        return <p class='info-message red'>{message.MOREPRODUCTS_SIGN_OTP_VALIDATION_ERROR}</p>;
      case 15: //Se ha superado el número máximo de intentos erróneos, una vez cargado el componente
        return <p class='info-message'>{message.MOREPRODUCTS_SIGN_OTP_EXCEEDED}</p>;
      case 16: //En carga inicial, cuando esta expirado o MaxAttempts, y con el boton de mostrar el reenvio
        return <p class='info-message'>{message.SIGN_OTP_EXPIRED_OR_CANCELLED}</p>;
      case 20:
        return <p class='info-message red'>{message.ERROR_LOADING_COMPONENT}</p>;
      case 21: //Expirado en carga inicial, sin mostrar boton de reenvio
        return <p class='info-message'>{message.ERROR_CANCELLED}</p>;
      case 22: //MaxAttempts en carga inicial, sin mostrar boton de reenvio
        return <p class='info-message'>{message.ERROR_EXPIRED}</p>;
      case 23:
        return <p class='info-message red'>{message.ERROR_OTP_SIGNED}</p>;
      case 24:
        return <p class='info-message red'>{message.ERROR_OTP_RESEND}</p>;
      case 30:
        return <p class='info-message gold'>{message.OTP_OK_SIGNED}</p>;
      default:
        return '';
    }
  }

  render() {
    const message = messages[this.localeState];

    if (this.idSignature === undefined || this.idSignature === '') {
      return <p class='text red'>{message.ERROR_LOADING_COMPONENT}</p>;
    }

    if (this.state === 0 ||
      (this.state >= 20 && this.state <= 23) ||
      this.state === 30) {
      return this.renderMessage();
    }

    if (this.state === 15 || this.state === 16) {
      return (<div>
        {this.renderMessage()}
        {this.showResendOtpLink &&
          <bst-button
            componentId='bst-otp-resend-button'
            isLoading={this.isLoading}
            text={message.OPERATIONS_FONDOSINVERSION_STEP3_REQUESTNEW}
            clickHandler={() => this.resendOTP(true)}
          >
          </bst-button>
        }
      </div>);
    }
    return (
      <div>
        <div>
          <div>
            {this.otpPin && <div id='bst-otp-pin' class='testing-otp-placeholder'>
              <span>{this.otpPin}</span>
            </div>}
            <div>
              <input
                id='bst-otp-input'
                class='otp-input'
                type='text'
                placeholder={this.textPlaceholder || message.MOREPRODUCTS_SIGN_OTP_PLACEHOLDER}
                value={this.otpValue}
                onKeyDown={(event: KeyboardEvent) => {
                  if (event.key === 'Enter') {
                    this.validateOTP();
                  }
                }}
                onInput={(event: InputEvent) => this.setOtpValue((event.currentTarget as HTMLInputElement).value)}>
              </input>
            </div>
            {this.showResendOtpLink &&
              <div class='resend-otp-container'>
                <p>{message.OPERATIONS_FONDOSINVERSION_STEP3_NOTRECEIVED}</p>
                <button class={`btn--link ${this.isLoading ? 'act-disabled' : ''}`}
                  onClick={() => { this.resendOTP(false) }}
                  disabled={this.isLoading}>
                  <span class={`resend-otp ${this.isLoading ? 'act-disabled' : ''}`}>{message.OPERATIONS_FONDOSINVERSION_STEP3_REQUEST}</span>
                </button>
              </div>
            }
            <div>
              <bst-button
                componentId='bst-otp-button'
                isLoading={this.isLoading}
                text={this.textButton}
                clickHandler={() => this.validateOTP()}
              >
              </bst-button>
              {this.showNoPresentLink && (
                <button
                  id='bst-otp-skip-investor'
                  class={`btn--link ${this.isLoading ? 'act-disabled' : ''}`}
                  onClick={() => this.notPresent()}
                  disabled={this.isLoading}>
                  <span>{message.SIGN_SKIP_INVESTOR}</span>
                </button>
              )}
            </div>
            {this.renderMessage()}
          </div>
        </div>
      </div >
    );
  }
}